section.code:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://faion.net/schemas/refactoring-patterns-playbook.json",
  "type": "object",
  "required": ["target", "steps", "version", "last_reviewed"],
  "properties": {
    "target":  {"type": "string", "description": "module / file path under refactor"},
    "steps": {
      "type": "array",
      "minItems": 1,
      "items": {
        "type": "object",
        "required": ["transform", "scope_files", "tests_green_before", "tests_green_after"],
        "properties": {
          "transform": {"enum": [
            "extract-method", "extract-class", "rename",
            "replace-conditional-with-polymorphism", "decompose-conditional",
            "introduce-parameter-object", "replace-magic-number",
            "replace-derived-variable-with-query", "move-method"
          ]},
          "scope_files": {"type": "array", "items": {"type": "string"}, "maxItems": 5},
          "before_pointer": {"type": "string", "description": "git rev:path:line"},
          "after_pointer":  {"type": "string"},
          "tests_green_before": {"type": "boolean", "const": true},
          "tests_green_after":  {"type": "boolean", "const": true},
          "rollback": {"type": "string", "description": "git revert sha"}
        }
      }
    },
    "version":       {"type": "string", "pattern": "^\\d+\\.\\d+\\.\\d+$"},
    "last_reviewed": {"type": "string", "format": "date"}
  }
}
